            try {
                var vClass = Java.use("G0.v");
                vClass.c.implementation = function (activity) {
                    console.log("[FRIDA] G0.v.c invoked with Activity: " + activity.getClass().getName());
                    var jsonObject = this.c(activity); // Call original method to get the JSONObject
                    console.log("[FRIDA] JSON Data for FirebaseAnalytics (Level: " + this.a.value + "): " + jsonObject.toString());

                    // You could inspect or modify 'jsonObject' here if needed
                    // Example: jsonObject.put("frida_flag", true);
                    return jsonObject;
                };
                console.log("[FRIDA] Hooked G0.v.c successfully.");
            } catch (e) {
