                            console.log("  Arg3 (JSON Object Content): " + param3);
                            console.log("[*** End F0.Q.m Intercept ***]");

                            // Call the original method to ensure app functionality
                            return this.m(param1, param2, param3);
                        };
                        console.log("[+] Hooked F0.Q.m successfully.");
                    } else {
                        console.log("[-] F0.Q class not found.");
                    }
